#!/usr/bin/env bash

# =============================================================================
# Database Maintenance Toolkit
# Executes SQL maintenance commands securely WITHOUT eval
# =============================================================================

set -euo pipefail

readonly SCRIPT_NAME="$(basename "$0")"
readonly LOG_FILE="/var/log/db_maintenance.log"

# Allowed maintenance commands (whitelist approach)
readonly ALLOWED_COMMANDS=(
    "ANALYZE TABLE"
    "OPTIMIZE TABLE"
    "CHECK TABLE"
    "REPAIR TABLE"
    "SHOW TABLE STATUS"
    "SHOW PROCESSLIST"
    "SHOW DATABASES"
    "SHOW TABLES"
    "SELECT COUNT"
    "FLUSH TABLES"
    "FLUSH PRIVILEGES"
    "FLUSH LOGS"
)

usage() {
    cat <<EOF
Usage: $SCRIPT_NAME [OPTIONS] -c "SQL_COMMAND"

Database Maintenance Toolkit - Execute maintenance SQL commands securely.

Options:
    -c, --command "SQL"    SQL command to execute (required)
    -d, --database DB      Target database (optional)
    -u, --user USER        MySQL user (default: root)
    -H, --host HOST        MySQL host (default: localhost)
    -p, --port PORT        MySQL port (default: 3306)
    -f, --force            Skip confirmation prompt
    -n, --dry-run          Show command without executing
    -h, --help             Show this help message

Allowed SQL operations:
$(printf '    - %s\n' "${ALLOWED_COMMANDS[@]}")

Examples:
    $SCRIPT_NAME -c "ANALYZE TABLE my_table" -d mydb
    $SCRIPT_NAME -c "SHOW PROCESSLIST"
    $SCRIPT_NAME -c "OPTIMIZE TABLE users" -d production -f
    $SCRIPT_NAME -c "CHECK TABLE orders" -d shop --dry-run
EOF
    exit 0
}

log_message() {
    local level="$1"
    local message="$2"
    local timestamp
    timestamp="$(date '+%Y-%m-%d %H:%M:%S')"
    echo "[$timestamp] [$level] $message" | tee -a "$LOG_FILE" >&2
}

# Validate that the SQL command matches our whitelist
validate_command() {
    local sql_command="$1"
    local upper_command
    upper_command="$(echo "$sql_command" | tr '[:lower:]' '[:upper:]' | xargs)"

    # Reject dangerous patterns regardless of whitelist
    local dangerous_patterns=(
        "DROP "
        "DELETE "
        "TRUNCATE "
        "ALTER "
        "INSERT "
        "UPDATE "
        "GRANT "
        "REVOKE "
        "CREATE "
        "LOAD "
        "INTO OUTFILE"
        "INTO DUMPFILE"
        "UNION "
        ";\s*"
        "--"
        "/\\*"
        "\\*/"
        "SLEEP("
        "BENCHMARK("
        "CHAR("
        "0x"
    )

    for pattern in "${dangerous_patterns[@]}"; do
        if [[ "$upper_command" =~ $pattern ]]; then
            log_message "ERROR" "BLOCKED dangerous pattern '$pattern' in command: $sql_command"
            echo "ERROR: Command contains forbidden pattern: '$pattern'" >&2
            echo "This command is not allowed for safety reasons." >&2
            return 1
        fi
    done

    # Check against whitelist
    local allowed=false
    for allowed_cmd in "${ALLOWED_COMMANDS[@]}"; do
        if [[ "$upper_command" == "${allowed_cmd}"* ]]; then
            allowed=true
            break
        fi
    done

    if [[ "$allowed" != true ]]; then
        log_message "ERROR" "REJECTED non-whitelisted command: $sql_command"
        echo "ERROR: Command not in allowed list." >&2
        echo "Run '$SCRIPT_NAME --help' to see allowed operations." >&2
        return 1
    fi

    # Reject multiple statements (semicolons within the command)
    local stripped
    stripped="$(echo "$sql_command" | sed 's/;[[:space:]]*$//')"
    if [[ "$stripped" == *";"* ]]; then
        log_message "ERROR" "BLOCKED multi-statement command: $sql_command"
        echo "ERROR: Multiple SQL statements are not allowed." >&2
        return 1
    fi

    return 0
}

# Read password securely
get_password() {
    local password

    # Try environment variable first (for automated/CI use)
    if [[ -n "${MYSQL_MAINTENANCE_PASSWORD:-}" ]]; then
        echo "$MYSQL_MAINTENANCE_PASSWORD"
        return 0
    fi

    # Try MySQL config file
    if [[ -f "$HOME/.my.cnf" ]]; then
        log_message "INFO" "Using credentials from ~/.my.cnf"
        echo "__USE_MY_CNF__"
        return 0
    fi

    # Prompt interactively
    if [[ -t 0 ]]; then
        read -rsp "Enter MySQL password: " password
        echo >&2
        echo "$password"
        return 0
    fi

    log_message "ERROR" "No password source available"
    echo "ERROR: No MySQL password available." >&2
    echo "Set MYSQL_MAINTENANCE_PASSWORD env var, configure ~/.my.cnf, or run interactively." >&2
    return 1
}

# Execute the SQL command securely — NO eval used
execute_sql() {
    local user="$1"
    local host="$2"
    local port="$3"
    local database="$4"
    local password="$5"
    local sql_command="$6"

    local -a mysql_args=()
    mysql_args+=(--user="$user")
    mysql_args+=(--host="$host")
    mysql_args+=(--port="$port")

    if [[ "$password" != "__USE_MY_CNF__" ]]; then
        mysql_args+=(--password="$password")
    fi

    if [[ -n "$database" ]]; then
        mysql_args+=(--database="$database")
    fi

    # Use --execute flag with the command passed as a proper argument
    # This is safe because mysql handles the argument as a SQL string,
    # not as a shell-interpreted value
    mysql_args+=(--execute="$sql_command")

    # Additional safety flags
    mysql_args+=(--safe-updates)
    mysql_args+=(--connect-timeout=10)

    # Execute mysql directly — arguments are passed safely via array expansion
    mysql "${mysql_args[@]}"
}

main() {
    local sql_command=""
    local database=""
    local user="root"
    local host="localhost"
    local port="3306"
    local force=false
    local dry_run=false

    # Parse arguments
    while [[ $# -gt 0 ]]; do
        case "$1" in
            -c|--command)
                sql_command="$2"
                shift 2
                ;;
            -d|--database)
                database="$2"
                shift 2
                ;;
            -u|--user)
                user="$2"
                shift 2
                ;;
            -H|--host)
                host="$2"
                shift 2
                ;;
            -p|--port)
                port="$2"
                shift 2
                ;;
            -f|--force)
                force=true
                shift
                ;;
            -n|--dry-run)
                dry_run=true
                shift
                ;;
            -h|--help)
                usage
                ;;
            *)
                echo "ERROR: Unknown option: $1" >&2
                usage
                ;;
        esac
    done

    # Validate required arguments
    if [[ -z "$sql_command" ]]; then
        echo "ERROR: SQL command is required. Use -c \"SQL_COMMAND\"" >&2
        echo "Run '$SCRIPT_NAME --help' for usage information." >&2
        exit 1
    fi

    # Validate port is numeric
    if ! [[ "$port" =~ ^[0-9]+$ ]]; then
        echo "ERROR: Port must be numeric." >&2
        exit 1
    fi

    # Validate the SQL command against whitelist
    if ! validate_command "$sql_command"; then
        exit 1
    fi

    log_message "INFO" "Validated command: $sql_command (user=$user, host=$host, db=${database:-N/A})"

    # Dry run mode
    if [[ "$dry_run" == true ]]; then
        echo "=== DRY RUN ==="
        echo "User:     $user"
        echo "Host:     $host:$port"
        echo "Database: ${database:-<none>}"
        echo "Command:  $sql_command"
        echo "==============="
        log_message "INFO" "Dry run completed for: $sql_command"
        exit 0
    fi

    # Confirmation prompt
    if [[ "$force" != true ]] && [[ -t 0 ]]; then
        echo "About to execute:"
        echo "  SQL:      $sql_command"
        echo "  Server:   $user@$host:$port"
        echo "  Database: ${database:-<default>}"
        echo ""
        read -rp "Proceed? [y/N]: " confirm
        if [[ "$confirm" != [yY] && "$confirm" != [yY][eE][sS] ]]; then
            log_message "INFO" "User cancelled: $sql_command"
            echo "Cancelled."
            exit 0
        fi
    fi

    # Get password securely
    local password
    password="$(get_password)" || exit 1

    # Execute the command securely
    log_message "INFO" "Executing: $sql_command"

    local output
    local exit_code=0
    output="$(execute_sql "$user" "$host" "$port" "$database" "$password" "$sql_command" 2>&1)" || exit_code=$?

    if [[ $exit_code -eq 0 ]]; then
        log_message "INFO" "SUCCESS: $sql_command"
        if [[ -n "$output" ]]; then
            echo "$output"
        else
            echo "Command executed successfully."
        fi
    else
        log_message "ERROR" "FAILED (exit=$exit_code): $sql_command — $output"
        echo "ERROR: Command failed with exit code $exit_code" >&2
        echo "$output" >&2
        exit $exit_code
    fi
}

main "$@"